item.content:encoded:
.custom-logo{max-width:168px;height:auto}
.acms-list__pros-cons li{padding:0px!important}
.acms-list__cons ul:not([class]) li:before{top: 0.58em!important;}
.post-content ul:not([class]) li:before{top: 0.7em;}

.page-template-default .post-content ul:not([class]) li:before {
    top: .7em;
}
ul.wp-block-list {
  list-style: disc;
}

ul.wp-block-list li {
  position: relative;
  padding-left: 12px;
  margin-bottom: 10px;
}
ul.wp-block-list li:empty {
  display: none;
}
.page-header__background{position:inherit!important}
